#[op_interface_impl]
impl MirToLlvmConversion for ActiveMaskOp {
    fn convert(
        &self,
        ctx: &mut Context,
        rewriter: &mut DialectConversionRewriter,
        operands_info: &OperandsInfo,
    ) -> Result<()> {
        let op = self.get_operation();
        match context::lowering_options(ctx).intrinsic_backend {
            IntrinsicBackend::LlvmNvptx => convert_active_mask(ctx, rewriter, op, operands_info),
            IntrinsicBackend::LibNvvm => {
                let i32_ty = IntegerType::get(ctx, 32, Signedness::Signless);
                let inline_asm = inline_asm_convergent(
                    ctx,
                    rewriter,
                    i32_ty.into(),
                    vec![],
                    "activemask.b32 $0;",
                    "=r,~{memory}",
                );
                rewriter.replace_operation(ctx, op, inline_asm);
                Ok(())
            }
        }
    }
}

